{
  "tool": "search_files_by_filename",
  "args": {
    "filename": "client-meeting-minutes.docx"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the following JSON list of files: <tool_result_0/>, extract the content of the first file and output it as plain text."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the following JSON list of files: <tool_result_0/>, extract the file_id of the first file and output it."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Given the following meeting minutes content: <tool_result_1/>, produce a concise summary (no more than three sentences) of the meeting and also provide the date of the next meeting in YYYY-MM-DD format. Output the summary, then a newline, then the date on a separate line."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Extract the date in YYYY-MM-DD format from the following text: <tool_result_3/>."
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Extract the summary (everything before the date) from the following text: <tool_result_3/>."
  }
}
{
  "tool": "search_contacts_by_name",
  "args": {
    "query": "client"
  }
}
{
  "tool": "query_llm",
  "args": {
    "prompt": "Extract the email address of the client from the following contacts list: <tool_result_6/>."
  }
}
{
  "tool": "send_email",
  "args": {
    "recipients": ["<tool_result_7/>"],
    "subject": "Summary of the client meeting",
    "body": "<tool_result_5/> The next meeting is scheduled for <tool_result_4/>.",
    "attachments": [
      {
        "type": "file",
        "file_id": "<tool_result_2/>"
      }
    ],
    "cc": null,
    "bcc": null
  }
}
